(function () {
  window.QRCode = window.QRCode || {};
  window.QRCode.toCanvas = function (canvas, text, options) {
    return new Promise(function (resolve, reject) {
      if (!canvas || !canvas.getContext) {
        reject(new Error("Canvas no disponible"));
        return;
      }
      var width = options && options.width ? Number(options.width) : 150;
      var image = new Image();
      image.onload = function () {
        canvas.width = width;
        canvas.height = width;
        var ctx = canvas.getContext("2d");
        ctx.clearRect(0, 0, width, width);
        ctx.drawImage(image, 0, 0, width, width);
        resolve();
      };
      image.onerror = function () {
        reject(new Error("No se pudo cargar el QR"));
      };
      image.src = "/api/qr?width=" + encodeURIComponent(width) + "&text=" + encodeURIComponent(text);
    });
  };
})();
